const raw = $input.first().json;
const input = raw.body || raw;

if (!input.document_base64) {
  throw new Error('Kein document_base64 übergeben. Dieser Workflow erwartet ein PDF-Dokument.');
}

const binaryData = Buffer.from(input.document_base64, 'base64');
const mimeType = input.mime_type || 'application/pdf';
const fileName = mimeType === 'application/pdf' ? 'document.pdf' : 'document';

const newItem = {
  json: {
    prompt: input.prompt || 'Extrahiere EXAKT die Daten aus diesem Dokument. ERFINDE NICHTS.',
    step_key: input.step_key || 'unknown',
    mime_type: mimeType,
    document_base64: input.document_base64,
    fallback_chain: [],
    start_time: Date.now()
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      binaryData,
      fileName,
      mimeType
    )
  }
};

return [newItem];

const input = $('Prepare Requests').first().json;
// content can be array [{type:"text", text:"..."}] or string
const raw = $json.content;
const text = Array.isArray(raw) ? raw.map(c => c.text || '').join('') : (raw || '');

return [{
  json: {
    text: text,
    model_used: 'claude-sonnet-4-20250514',
    fallback_chain: ['claude-sonnet-4'],
    total_attempts: 1,
    processing_time_ms: Date.now() - input.start_time,
    step_key: input.step_key,
    success: true
  }
}];

