const input = $('Prepare Requests').first().json;

// Sammle die Fehler-Details von jedem Modell
const claudeError = $('Call Claude').first()?.json?.error || 'unknown';
const geminiError = $('Call Gemini').first()?.json?.error || 'unknown';
const gptError = $('Call Chat GPT').first()?.json?.error || 'unknown';

return [{
  json: {
    text: null,
    model_used: null,
    fallback_chain: ['claude-sonnet-4', 'gemini-2.0-flash', 'gpt-4o'],
    total_attempts: 3,
    processing_time_ms: Date.now() - input.start_time,
    step_key: input.step_key,
    success: false,
    error: 'All 3 AI models failed',
    error_details: {
      claude: claudeError,
      gemini: geminiError,
      gpt: gptError
    }
  }
}];

const result = $input.first().json;

// Log to Supabase using n8n's built-in HTTP helper
try {
  const supabaseUrl = 'https://yetwntwayhmzmhhgdkli.supabase.co';
  const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InlldHdudHdheWhtem1oaGdka2xpIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjUyODQ1MDcsImV4cCI6MjA4MDg2MDUwN30.uZOrOtOsQ5M0jVEByM7N6gUsgleebKKWw-1EJPmuz3Y';

  await this.helpers.httpRequest({
    method: 'POST',
    url: `${supabaseUrl}/rest/v1/workflow_steps`,
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json',
      'Prefer': 'resolution=merge-duplicates'
    },
    body: {
      step_key: result.step_key || 'unknown',
      step_type: 'AI_DOCUMENT_ANALYSIS',
      status: result.success ? 'COMPLETED' : 'FAILED',
      model_used: result.model_used || null,
      fallback_chain: result.fallback_chain || [],
      attempt_count: result.total_attempts || 1,
      max_attempts: 3,
      error: result.success ? null : {
        message: result.error || 'Unknown error',
        details: result.error_details || null
      },
      next_retry_at: result.success ? null : new Date(Date.now() + 15 * 60 * 1000).toISOString(),
      completed_at: result.success ? new Date().toISOString() : null
    }
  });
} catch (e) {
  // Don't fail the workflow if logging fails
  result.log_error = e.message;
}

return [{ json: result }];

